using UnityEngine;

public class rot : MonoBehaviour
{
    public Transform centerPoint; // 你给定的旋转中心点
    public float speed = 50f;     // 旋转速度

    void Update()
    {
        transform.RotateAround(
            centerPoint.position, // 绕哪个点
            Vector3.forward,      // 旋转轴：Z轴，适合2D
            speed * Time.deltaTime
        );
    }
}

